{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex optimization task involving spatial search, pattern matching, and cost minimization. I will break it down into geometric modeling, query strategy optimization, and cost estimation.",
  "helpers": [
    {
      "label": "geometry_modeler",
      "instructions": "Represent the known polyomino shapes as sets of relative coordinates. For each shape, identify its bounding box, symmetry properties, and possible rotation/reflection variants to ensure all possible orientations are accounted for in the search space."
    },
    {
      "label": "query_optimizer",
      "instructions": "Develop a strategy for using noisy aggregate queries. Given a set of candidate placements for the polyominoes, determine the optimal sequence of query regions (subsets of cells) that maximizes information gain regarding the presence of oil while minimizing the number of queries and the impact of noise."
    },
    {
      "label": "probing_cost_analyzer",
      "instructions": "Create a cost function that calculates the total expected cost based on the number of individual drilling actions, the number of aggregate queries used, and the penalty for incorrect final guesses. This function should allow for comparing different search strategies."
    }
  ],
  "synthesis_brief": "Combine the geometric representations of the polyominoes with the optimized query strategy to simulate a search process. Use the cost analyzer to evaluate the efficiency of the strategy and select the sequence of actions that minimizes the total expected cost to identify all oil-containing cells."
}

